class Solution {
    public int[] maxDepthAfterSplit(String seq) {
        int n = seq.length();
        int[] res = new int[n];
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (seq.charAt(i) == '(') {
                res[i] = count % 2;
                count++;
            } else {
                res[i] = 1 - (count % 2);
                count--;
            }
        }
        return res;
    }
}
```

